class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null
    private var cameraImageUri: Uri? = null
    private lateinit var jsBridge: JavaScriptBridge
    
    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            jsBridge.handleCameraPermissionResult(true)
        } else {
            jsBridge.handleCameraPermissionResult(false)
        }
    }
    
    private val notificationPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            jsBridge.handleNotificationPermissionResult(true)
        } else {
            jsBridge.handleNotificationPermissionResult(false)
        }
    }
    
    private val cameraLauncher = registerForActivityResult(
        ActivityResultContracts.TakePicture()
    ) { success ->
        if (success && cameraImageUri != null) {
            jsBridge.handleCameraResult(cameraImageUri!!)
        } else {
            jsBridge.handleCameraError("Failed to capture image")
        }
    }
    
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val data = result.data
            val results = if (data == null) {
                cameraImageUri?.let { arrayOf(it) }
            } else {
                data.data?.let { arrayOf(it) }
            }
            fileUploadCallback?.onReceiveValue(results)
        } else {
            fileUploadCallback?.onReceiveValue(null)
        }
        fileUploadCallback = null
        cameraImageUri = null
    }

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupWebView()
        createNotificationChannel()
        
        webView.loadUrl("https://your-web-app-url.com")
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
        }
        
        jsBridge = JavaScriptBridge(this, webView)
        webView.addJavascriptInterface(jsBridge, "NativeBridge")
        
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView, url: String): Boolean {
                return false
            }
        }
        
        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView,
                filePathCallback: ValueCallback<Array<Uri>>,
                fileChooserParams: FileChooserParams
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback
                
                val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                cameraImageUri = createImageUri()
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
                
                val contentSelectionIntent = Intent(Intent.ACTION_GET_CONTENT)
                contentSelectionIntent.addCategory(Intent.CATEGORY_OPENABLE)
                contentSelectionIntent.type = "image/*"
                
                val intentArray = arrayOf(takePictureIntent)
                
                val chooserIntent = Intent(Intent.ACTION_CHOOSER)
                chooserIntent.putExtra(Intent.EXTRA_INTENT, contentSelectionIntent)
                chooserIntent.putExtra(Intent.EXTRA_TITLE, "Select Image")
                chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray)
                
                fileChooserLauncher.launch(chooserIntent)
                return true
            }
        }
    }

    private fun createImageUri(): Uri? {
        val contentValues = ContentValues().apply {
            put(MediaStore.Images.Media.DISPLAY_NAME, "IMG_${System.currentTimeMillis()}.jpg")
            put(MediaStore.Images.Media.MIME_TYPE, "image/jpeg")
        }
        return contentResolver.insert(MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                "default_channel",
                "Default Notifications",
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Default notification channel"
            }
            
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    fun requestCameraPermission() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) 
            != PackageManager.PERMISSION_GRANTED) {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        } else {
            jsBridge.handleCameraPermissionResult(true)
        }
    }

    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS)
                != PackageManager.PERMISSION_GRANTED) {
                notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            } else {
                jsBridge.handleNotificationPermissionResult(true)
            }
        } else {
            jsBridge.handleNotificationPermissionResult(true)
        }
    }

    fun launchCamera() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED) {
            cameraImageUri = createImageUri()
            cameraImageUri?.let {
                cameraLauncher.launch(it)
            }
        } else {
            jsBridge.handleCameraError("Camera permission not granted")
        }
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }
}

class JavaScriptBridge(
    private val activity: MainActivity,
    private val webView: WebView
) {
    private val localStorage = LocalStorageManager(activity)
    private val notificationManager = NotificationHelper(activity)

    @JavascriptInterface
    fun requestCameraAccess() {
        activity.runOnUiThread {
            activity.requestCameraPermission()
        }
    }

    @JavascriptInterface
    fun capturePhoto() {
        activity.runOnUiThread {
            activity.launchCamera()
        }
    }

    @JavascriptInterface
    fun saveToLocalStorage(key: String, value: String): Boolean {
        return localStorage.save(key, value)
    }

    @JavascriptInterface
    fun getFromLocalStorage(key: String): String? {
        return localStorage.get(key)
    }

    @JavascriptInterface
    fun removeFromLocalStorage(key: String): Boolean {
        return localStorage.remove(key)
    }

    @JavascriptInterface
    fun clearLocalStorage(): Boolean {
        return localStorage.clear()
    }

    @JavascriptInterface
    fun getAllLocalStorageKeys(): String {
        return localStorage.getAllKeys().toString()
    }

    @JavascriptInterface
    fun requestNotificationPermission() {
        activity.runOnUiThread {
            activity.requestNotificationPermission()
        }
    }

    @JavascriptInterface
    fun showNotification(title: String, message: String, notificationId: Int) {
        activity.runOnUiThread {
            notificationManager.showNotification(title, message, notificationId)
        }
    }

    @JavascriptInterface
    fun cancelNotification(notificationId: Int) {
        activity.runOnUiThread {
            notificationManager.cancelNotification(notificationId)
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val deviceInfo = JSONObject()
        deviceInfo.put("model", Build.MODEL)
        deviceInfo.put("manufacturer", Build.MANUFACTURER)
        deviceInfo.put("osVersion", Build.VERSION.RELEASE)
        deviceInfo.put("sdkVersion", Build.VERSION.SDK_INT)
        return deviceInfo.toString()
    }

    @JavascriptInterface
    fun saveFile(filename: String, content: String): Boolean {
        return try {
            val file = File(activity.filesDir, filename)
            FileOutputStream(file).use { output ->
                output.write(content.toByteArray())
            }
            true
        } catch (e: Exception) {
            e.printStackTrace()
            false
        }
    }

    @JavascriptInterface
    fun readFile(filename: String): String? {
        return try {
            val file = File(activity.filesDir, filename)
            if (file.exists()) {
                FileInputStream(file).bufferedReader().use { it.readText() }
            } else {
                null
            }
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    @JavascriptInterface
    fun deleteFile(filename: String): Boolean {
        return try {
            val file = File(activity.filesDir, filename)
            file.delete()
        } catch (e: Exception) {
            e.printStackTrace()
            false
        }
    }

    @JavascriptInterface
    fun vibrate(milliseconds: Long) {
        activity.runOnUiThread {
            val vibrator = activity.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                vibrator.vibrate(
                    android.os.VibrationEffect.createOneShot(
                        milliseconds,
                        android.os.VibrationEffect.DEFAULT_AMPLITUDE
                    )
                )
            } else {
                @Suppress("DEPRECATION")
                vibrator.vibrate(milliseconds)
            }
        }
    }

    fun handleCameraPermissionResult(granted: Boolean) {
        val script = "javascript:window.onCameraPermissionResult && window.onCameraPermissionResult($granted)"
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }

    fun handleNotificationPermissionResult(granted: Boolean) {
        val script = "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult($granted)"
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }

    fun handleCameraResult(imageUri: Uri) {
        val script = "javascript:window.onCameraSuccess && window.onCameraSuccess('$imageUri')"
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }

    fun handleCameraError(error: String) {
        val script = "javascript:window.onCameraError && window.onCameraError('$error')"
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }
